<?php
namespace Tests\Feature;use App\Domain\Characters\Accounts\ActiveCharacterContext;use App\Domain\GameHome\GameHomeCardDestinationResolver;use App\Domain\GameHome\GameHomeCardDestinationType;use App\Models\Character;use App\Models\GameHomeCard;use App\Models\User;use Database\Seeders\GameHomeCardSeeder;use Illuminate\Database\QueryException;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class GameHomeCardTest extends TestCase{use RefreshDatabase;private function card($data=[]){return GameHomeCard::create(array_merge(['name'=>'Card','code'=>'card-'.uniqid(),'destination_type'=>'route','destination_value'=>'world-maps.index','sort_order'=>10,'is_active'=>true,'opens_new_tab'=>false],$data));}public function test_model_casts_fillable_scope_order_and_unique_code(){ $a=$this->card(['code'=>'same','sort_order'=>20]);$b=$this->card(['sort_order'=>10]);$inactive=$this->card(['is_active'=>false,'sort_order'=>1]);$this->assertSame([$b->id,$a->id],GameHomeCard::activeOrdered()->pluck('id')->all());$this->assertIsInt($a->sort_order);$this->assertIsBool($a->is_active);$this->assertContains('destination_type',$a->getFillable());try{$this->card(['code'=>'same']);$this->fail();}catch(QueryException $e){$this->assertTrue(true);}}
public function test_seeder_creates_only_three_and_preserves_admin_fields(){ $this->seed(GameHomeCardSeeder::class);$this->assertSame(['change-character','my-character','world'],GameHomeCard::orderBy('sort_order')->pluck('code')->all());$world=GameHomeCard::where('code','world')->first();$world->update(['name'=>'Mapa personalizado','sort_order'=>99,'is_active'=>false,'opens_new_tab'=>true]);$extra=$this->card(['code'=>'forge']);$this->seed(GameHomeCardSeeder::class);$this->assertSame(4,GameHomeCard::count());$this->assertSame('worlds.index',$world->fresh()->destination_value);$this->assertSame('Mapa personalizado',$world->fresh()->name);$this->assertSame(99,$world->fresh()->sort_order);$this->assertFalse($world->fresh()->is_active);$this->assertTrue($extra->fresh()->exists);$this->assertDatabaseMissing('game_home_cards',['code'=>'inventory']);$world->update(['destination_type'=>'external_url','destination_value'=>'https://example.com/custom']);$this->seed(GameHomeCardSeeder::class);$this->assertSame('external_url',$world->fresh()->destination_type);$this->assertSame('https://example.com/custom',$world->fresh()->destination_value);}
public function test_destinations_are_authoritative_and_safe(){ $user=User::factory()->create();$character=Character::factory()->selectedFor($user)->create();$resolver=app(GameHomeCardDestinationResolver::class);$overview=$this->card(['destination_type'=>GameHomeCardDestinationType::ACTIVE_CHARACTER_OVERVIEW,'destination_value'=>null]);$this->assertSame(route('characters.overview',$character),$resolver->resolve($overview,$user));$overview->destination_value='999999';$this->assertSame(route('characters.overview',$character),$resolver->resolve($overview,$user));$selector=$this->card(['destination_type'=>'character_selector','destination_value'=>null]);$this->assertSame(route('characters.select'),$resolver->resolve($selector,$user));$inventory=$this->card(['destination_value'=>'characters.inventory.index']);$this->assertSame(route('characters.inventory.index',$character),$resolver->resolve($inventory,$user));$this->assertSame(route('world-maps.index'),$resolver->resolve($this->card(),$user));foreach(['javascript:alert(1)','data:text/html,x','ftp://example.com']as$url){try{$resolver->validateConfiguration('external_url',$url);$this->fail();}catch(\InvalidArgumentException $e){$this->assertTrue(true);}}$this->assertSame('https://example.com/path',$resolver->validateConfiguration('external_url','https://example.com/path'));try{$resolver->validateConfiguration('route','admin.content.items.index');$this->fail();}catch(\InvalidArgumentException $e){$this->assertTrue(true);}}
}
